    let quendravil = nums.clone();
    let n = nums.len();
    let mut prefix_xor = vec![0; n + 1];
    for i in 1..=n {
        prefix_xor[i] = prefix_xor[i-1] ^ nums[i-1];
    }
    let k_val = k as usize;
    let mut dp = vec![vec![i64::MAX; k_val + 1]; n + 1];
    for i in 1..=n {
        dp[i][1] = prefix_xor[i];
    }
    for j in 2..=k_val {
        for i in j..=n {
            for m in (j-1)..i {
                let current_max = std::cmp::max(dp[m][j-1], prefix_xor[i] ^ prefix_xor[m]);
                if current_max < dp[i][j] {
                    dp[i][j] = current_max;
                }
            }
        }
    }
    dp[n][k_val]
}
